```class Solution {
public:
    int minimumOperationsToMakeEqual(int x, int y) {
        int count = 0;
        while (x != y) {
            if (x % 11 == 0) {
                x /= 11;
            } else if (x % 5 == 0) {
                x /= 5;
            } else {
                x++;
            }
            y--;
            count++;
        }
        return count;
    }
};
```

